import{_ as t,o as i,c as s,a3 as a}from"./chunks/framework.CjquFG0V.js";const A=JSON.parse('{"title":"40. Introduction Of Revised Allied Health Assistant","description":"","frontmatter":{"title":"40. Introduction Of Revised Allied Health Assistant","eba":"Health Allied & Managers Admin 2021-2025","topics":["classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/40-introduction-of-revised-allied-health-assistant.md","filePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/40-introduction-of-revised-allied-health-assistant.md"}'),n={name:"ebas/has-managers-admin/health-allied-services/classification-staffing/40-introduction-of-revised-allied-health-assistant.md"};function l(r,e,o,d,c,h){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="_40-introduction-of-revised-allied-health-assistant" tabindex="-1">40. Introduction Of Revised Allied Health Assistant <a class="header-anchor" href="#_40-introduction-of-revised-allied-health-assistant" aria-label="Permalink to &quot;40. Introduction Of Revised Allied Health Assistant&quot;">​</a></h1><p>Classification Structure</p><p><strong>40.1</strong> From FFPPOA 1 July 2021, Employees classified as Allied Health Assistants, Dietary Supervisor, Instructor Trades, Orthotic Technician or Social Worker/Welfare Aide will translate to the new Allied Health Assistant classification structure as follows:</p><p>Current classification New classification • Allied Health Assistant Grade 1 (Unqualified) Allied Health Assistant Grade 1 • Dietary Supervisor • Instructor Trades (Unqualified)</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p>• Social Worker/Welfare Aide • Orthotic Technician Grade 1 • Allied Health Assistant Grade 2 (Qualified) Allied Health Assistant Grade 2 • Instructor Trades (Qualified) less than 3 months • Allied Health Assistant Grade 3 (Qualified) • Orthotic Technician Grade 2 • Orthotic Technician Grade 3 Allied Health Assistant Grade 3 • Orthotic Technician Grade 4 • Orthotic Technician Grade 5 • Instructor Trades (Qualified) greater than 3 months</p><p><strong>40.2</strong> Within 3 months of the commencement of the Agreement, the Employers will review the existing Employees classified as Allied Health Assistant and confirm in writing to the those Employees:</p><p><strong>(a)</strong> to which classification they have translated, effective from FFPPOA 1 July</p><p><strong>(b)</strong> whether their duties change as a result of the translation</p><p><strong>(c)</strong> back payment of wages (if any) effective from FFPPOA 1 July 2021</p><p><strong>40.3</strong> Where an Employee disagrees with this re-classification, in the first instance the dispute will be dealt with by the AIC. If the matter remains in dispute, it will be dealt with in accordance with Section 1 <a href="/eba/ebas/has-managers-admin/health-allied-services/allowances/17-reimbursement-of-expenses-dhsv.html">clause 17</a> (Dispute Resolution Procedure).</p><p><strong>40.4</strong> Allied Health Assistant Review</p><p><strong>(a)</strong> The VHIA and HWU (together with equal representation from their respective memberships) will undertake a review of the Allied Health Assistant structure to examine duties associated with the Certificate IV in Training &amp; Assessment and other emerging Allied Health Assistant duties and responsibilities (including NDIS).</p><p><strong>(b)</strong> The review process in clause 40.4(a) will commence in 2022 and will include consultation with Allied Health Assistant Victorian Network (AHAVN).</p>',14)])])}const p=t(n,[["render",l]]);export{A as __pageData,p as default};
